-- Enrichment marathon batch: Redis, Redmine, Redocly, Reflect, Regie.ai, RELATE, RelativityOne, Relay Financial

-- ── Redis ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Redis is an open-source, in-memory data structure store used as a database, cache, message broker, and streaming engine, known for sub-millisecond performance.$q$, short_description),
  pricing_model = COALESCE($q$Freemium and usage-based: Redis Open Source is free to self-host; managed Redis Cloud offers free, pay-as-you-go, and enterprise tiers$q$, pricing_model),
  starting_price = COALESCE($q$Free (Redis Open Source and Redis Cloud free tier); Redis Cloud paid plans start around $5/month (Essentials) with Pro from about $200/month$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Approximately 1,500 employees (2025-2026)$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$Core written in C; official and community client libraries for Python, Java, Node.js, Go, C#, Ruby, PHP, and more$q$]::text[],
  seo_title = COALESCE($q$Redis Review 2026: Pricing, Features, and Licensing Explained$q$, seo_title),
  seo_meta_description = COALESCE($q$See what Redis costs in 2026, how its AGPLv3 licensing works after the 2024-2025 changes, and whether the in-memory database fits your stack.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Redis is a free, open-source, in-memory data structure store originally created in 2009 by Salvatore Sanfilippo (known online as antirez), who used it to solve real-time analytics problems at his startup. Redis is commonly used as a database, cache, message broker, and streaming engine, prized for sub-millisecond read and write latency and native support for data structures such as strings, hashes, lists, sets, sorted sets, streams, and geospatial indexes. The company behind Redis, originally called Redis Labs and now known as Redis Ltd. (also referred to as Redis Inc.), was founded in 2011 by Ofer Bengal and Yiftach Shoolman and is headquartered in San Francisco, California, after relocating from Mountain View in 2024; as of 2025-2026 the company employs roughly 1,500 people and reported around 272.6 million dollars in annual recurring revenue with a valuation near 2 billion dollars. Redis's licensing has changed significantly in recent years, which is important for anyone evaluating the project: the software was originally released under the permissive BSD 3-Clause license, but in March 2024 Redis Labs switched future versions to a dual license of the Redis Source Available License (RSALv2) and the Server Side Public License (SSPLv1), moves that were not recognized as open source by the Open Source Initiative and prompted the community-led Valkey fork under the Linux Foundation. After that licensing change failed to gain community acceptance, and following antirez's return to the company as a developer advocate in mid-2024, Redis reversed course in May 2025 and began offering Redis 8 and later versions under a tri-license model that includes the AGPLv3 open-source license alongside RSALv2 and SSPLv1, effectively bringing Redis back into OSI-recognized open source territory. As part of this update, previously separate Redis Stack modules, RediSearch, RedisJSON, RedisTimeSeries, and RedisBloom, were folded into Redis 8 as built-in capabilities. For teams that do not want to self-host, Redis Ltd. sells a managed Redis Cloud service with a free tier (30 MB, shared infrastructure), Essentials plans priced roughly 5 to 216 dollars per month for dedicated small-to-mid-size databases, and Pro plans starting around 200 dollars per month for production workloads on dedicated VPC infrastructure with multi-availability-zone high availability and a 99.999 percent uptime SLA; Enterprise and self-managed Redis Software options are also available with custom pricing. Because of its speed and flexible data structures, Redis is widely used for caching, session storage, real-time leaderboards, rate limiting, pub/sub messaging, and increasingly as a vector database for AI and retrieval-augmented generation workloads.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'edd1bac6-16dc-4bda-b79f-aadb3cc602d0';

