-- ── Redocly ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Redocly is an API documentation and developer portal platform built around the popular open-source Redoc renderer, helping teams publish, govern, and manage OpenAPI docs.$q$, short_description),
  pricing_model = COALESCE($q$Freemium, seat-based subscription with separate usage-based add-ons$q$, pricing_model),
  starting_price = COALESCE($q$Free (Redoc open-source renderer, MIT license); paid plans start at $10/seat/month (Pro)$q$, starting_price),
  founded_year = COALESCE(2017, founded_year),
  company_size = COALESCE($q$Approximately 50 employees$q$, company_size),
  headquarters = COALESCE($q$Austin, Texas, USA$q$, headquarters),
  languages = ARRAY[$q$Platform built primarily in TypeScript/JavaScript; supports OpenAPI, AsyncAPI, GraphQL, and SOAP documentation formats$q$]::text[],
  seo_title = COALESCE($q$Redocly Review 2026: Pricing, Features, and API Documentation Tools$q$, seo_title),
  seo_meta_description = COALESCE($q$Explore Redocly's pricing plans, Redoc renderer, developer portal, and API governance tools for teams publishing OpenAPI documentation.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Redocly is an API documentation and developer experience platform founded in 2017, headquartered in Austin, Texas, with roughly 50 employees. The company started as the team behind Redoc, an open-source, MIT-licensed alternative to Swagger UI that renders OpenAPI, and now also AsyncAPI, GraphQL, and SOAP, specifications into clean, three-panel API reference documentation; Redoc remains free to self-host or embed and is widely used, ranking among the most popular API documentation tools on GitHub and npm. On top of the free renderer, Redocly sells a commercial platform for building and governing developer portals, combining several named products: Redoc (the reference documentation renderer), Revel (a developer portal builder supporting Markdown docs, custom React pages, and localization), Reef (an API catalog and governance tool with scorecards and API discovery), and a combined bundle called Realm. Redocly's commercial pricing is seat-based: the Pro plan starts at 10 dollars per seat per month and includes one project, up to 100 pages, custom-domain hosting, mock servers, and linting; the Enterprise plan is 24 dollars per seat per month and adds single sign-on, guest SSO, role-based access control, AI-powered search, analytics, and MCP server support, with page limits raised to 500; an Enterprise+ tier is available with custom, annually billed pricing for organizations that need data residency options, single-tenant hosting, procurement support, security questionnaires, and dedicated professional services. The Revel and Reef add-on products can be purchased individually, roughly 10 dollars per seat per month on Pro or 24 dollars per seat per month on Enterprise, or bundled together as Realm for 18 dollars per seat per month on Pro or 42 dollars per seat per month on Enterprise. Redocly also offers a separate usage-based product for monitoring API reliability, with a free tier covering the first 1,000 requests per month and paid commitment tiers ranging from 100 dollars per month for 20,000 requests up to 1,000 dollars per month for 500,000 requests, plus per-request overage pricing. Redocly's target customers are engineering and API platform teams that need to publish accurate, governed, and well-designed API reference documentation and developer portals at scale, positioning it as an alternative to tools like Swagger UI, Stoplight, and ReadMe.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '01c9cb83-d21b-4761-b79e-7d589ccbad23';

