-- ── RELATE ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RELATE is an open-source, Django-based online courseware platform created by Andreas Kloeckner for building and delivering interactive university-style courses.$q$, short_description),
  pricing_model = COALESCE($q$Free and open source (self-hosted)$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2014, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$Built with Python/Django; course content authored in YAML and Markdown$q$]::text[],
  seo_title = COALESCE($q$RELATE Courseware Review: Open-Source Online Course Platform$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn about RELATE, Andreas Kloeckner's open-source Django courseware platform for interactive university course delivery, grading, and content.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RELATE is a free, open-source, web-based courseware platform created by Andreas Kloeckner, a computer science professor, primarily for delivering interactive university-level online courses; the project's documentation carries a copyright notice spanning 2014 through 2025, indicating over a decade of active development, and its source code is maintained publicly on GitHub. Built on the Python-based Django web framework, RELATE is a niche, academic tool rather than a mainstream commercial SaaS product, and it is distributed at no cost for institutions and instructors willing to self-host it on their own infrastructure. The platform's central concept is the flow, a structured sequence of pages that combines static instructional content such as text and videos with interactive elements such as quizzes and sandboxed, auto-graded coding exercises, allowing instructors to build self-paced or scheduled learning modules. Course content itself is authored in a simple, version-controllable, text-based format using YAML for structure and Markdown for content, which lets instructors track changes to their courses using Git; RELATE explicitly supports Git-based workflows so instructors can preview and edit new course content while enrolled students continue to see a stable prior version until changes are published. Additional features include a built-in grade book, a class calendar, live in-class quiz functionality, sandboxed code execution with automatic grading and plotting support for programming assignments, human-in-the-loop grading workflows for open-ended responses, and support for hosting multiple independent courses on a single RELATE installation. The platform also includes in-class messaging via XMPP for real-time classroom interaction. Because RELATE is a specialized academic project rather than a general-purpose commercial product, it lacks the marketing presence, company backing, pricing tiers, or customer support infrastructure of mainstream learning management systems such as Canvas, Moodle, or Blackboard, and it is best understood as a purpose-built tool for technical and STEM courses, particularly ones with programming or computational components, taught by instructors comfortable with self-hosting Django applications and authoring course content in text-based formats. Its most notable adopter has been Kloeckner's own courses at the University of Illinois Urbana-Champaign, where RELATE has been used for numerical methods and scientific computing instruction.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9bf9becd-f896-4366-81eb-031d10afdd43';

