-- ── RelativityOne ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$RelativityOne is a cloud-based, AI-powered e-discovery and legal data intelligence platform from Relativity, used by law firms, corporations, and government agencies.$q$, short_description),
  pricing_model = COALESCE($q$Custom enterprise pricing, pay-as-you-go or 1-3 year commitments$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing (not publicly disclosed)$q$, starting_price),
  founded_year = COALESCE(2001, founded_year),
  company_size = COALESCE($q$Approximately 1,800-1,900 employees$q$, company_size),
  headquarters = COALESCE($q$Chicago, Illinois, USA$q$, headquarters),
  seo_title = COALESCE($q$RelativityOne Review 2026: Pricing, Features, and E-Discovery Tools$q$, seo_title),
  seo_meta_description = COALESCE($q$Learn how RelativityOne's cloud e-discovery platform works, who uses it, and how its custom pricing compares for legal and compliance teams.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$RelativityOne is the cloud-based, software-as-a-service version of Relativity, an e-discovery and legal data intelligence platform originally built by kCura, a Chicago-based software consulting firm founded in 2001 by Andrew Sieja. The company rebranded from kCura to Relativity in August 2017, taking the name of its flagship product, and remains headquartered in Chicago, Illinois, with roughly 1,800 to 1,900 employees as of 2025-2026 spread across the United States, Poland, the United Kingdom, and other locations; independent estimates put the company's annual recurring revenue near 235.9 million dollars with a valuation reported around 3.6 billion dollars. RelativityOne is hosted on Microsoft Azure and offers the full functionality of the original on-premises Relativity Server product as a secure, cloud-native SaaS platform, adding elastic scalability, built-in AI-powered review and analytics capabilities, and reduced infrastructure management burden for customers; Relativity also continues to offer Relativity Server as an on-premises deployment option for organizations with specific data residency or infrastructure requirements. The platform is used to manage the discovery, review, and analysis of large volumes of electronic data in litigation, internal investigations, and regulatory compliance matters, combining document review workflows, AI-assisted categorization and prioritization, data visualization, and case analytics. Relativity reports that RelativityOne and its broader platform serve more than 180,000 users across more than 40 countries, including customers such as the U.S. Department of Justice, more than 70 Fortune 100 companies, and 198 of the Am Law 200 largest law firms, making it one of the dominant platforms in the legal e-discovery software category alongside competitors like Everlaw, Reveal (Logikcull), and DISCO. Pricing for RelativityOne is not publicly published; Relativity structures it around flexible, predictable enterprise pricing models, offering customers the choice of pay-as-you-go consumption pricing or discounted one-year or three-year committed contracts, with exact costs determined by data volume, user counts, and workspace configuration through direct sales engagement. Because of its scale, AI capabilities, and deep adoption among major law firms and corporate legal departments, RelativityOne is generally positioned as an enterprise-grade platform rather than a self-serve tool for small legal teams.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '6b59bfb3-5ea0-4d33-92fe-b141944faacf';

