-- ── Relay Financial ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Relay is a business banking and money-management platform offering fee-free checking, multiple sub-accounts, cards, and cash-flow tools for small businesses.$q$, short_description),
  pricing_model = COALESCE($q$Freemium subscription: free Starter tier plus paid Grow and Scale plans$q$, pricing_model),
  starting_price = COALESCE($q$Free (Starter plan); paid plans from $30/month (Grow)$q$, starting_price),
  founded_year = COALESCE(2018, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Toronto, Ontario, Canada$q$, headquarters),
  seo_title = COALESCE($q$Relay Financial Review 2026: Pricing, Features, and Business Banking$q$, seo_title),
  seo_meta_description = COALESCE($q$See how Relay's business banking platform works, what its Starter, Grow, and Scale plans cost, and which features fit growing businesses.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Relay, also known as Relay Financial, is a business banking and cash-flow management platform founded in 2018 and headquartered in Toronto, Ontario, Canada. The company built an all-in-one banking product aimed at small and mid-sized businesses that need more control over multi-account cash management than a typical single-account business checking product provides; as with most U.S.-facing fintech banking products, Relay's accounts are held and insured through partner banks rather than Relay itself holding a banking charter. The platform's core feature is support for up to 20 individual checking accounts on the free plan, rising to up to 50 on higher tiers, so businesses can separate funds for taxes, payroll, reserves, and specific projects without opening accounts at multiple banks, alongside up to 50 virtual or physical Visa debit cards for employee spend control. Relay supports depositing funds via ACH transfer, wire, check, cash, and payouts from payment processors such as PayPal, Stripe, and Square, and supports sending money via ACH, wire, and check; it also syncs transaction data directly into QuickBooks Online and Xero for bookkeeping and reconciliation. Relay's pricing follows a three-tier freemium model: the Starter plan is free and includes up to 20 checking accounts and basic ACH functionality with no monthly account fees, no overdraft fees, and no minimum balance requirement; the Grow plan is 30 dollars per month and adds free outgoing domestic wires, automated bill pay, same-day ACH, and a higher-yield savings account around 1.55 percent APY; and the Scale plan is 90 dollars per month, which raises the checking account limit to 50, increases savings APY further to around 2.68 percent, and unlocks more advanced automation and financial workflow tools. Relay also offers up to two savings accounts with yields reported in the roughly 1 to 3 percent APY range depending on plan tier. Because it focuses specifically on multi-account organization, integrated bill pay, and accounting-software syncing rather than lending or investment products, Relay is generally positioned as a cash-flow and treasury-management-oriented alternative to traditional business checking accounts and other fintech competitors such as Mercury, Novo, and Bluevine.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '9a668def-7d55-49ba-9faf-7c5b9537b7a6';

