INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$In-memory data structures$q$, $q$Native support for strings, hashes, lists, sets, sorted sets, and streams enables far more than simple key-value caching.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Persistence options$q$, $q$RDB snapshotting and append-only file (AOF) logging let Redis balance performance with durability.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Pub/Sub and streams$q$, $q$Built-in publish/subscribe messaging and Redis Streams support real-time event and messaging architectures.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Bundled search and JSON$q$, $q$RediSearch and RedisJSON capabilities are now built into Redis 8, enabling full-text search and native JSON document storage.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Replication and clustering$q$, $q$Redis Cluster and replication provide horizontal scaling and high availability for production workloads.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Vector search for AI/RAG$q$, $q$Native vector data types and similarity search support retrieval-augmented generation and AI application backends.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Lua scripting and functions$q$, $q$Server-side scripting allows atomic, custom logic to run directly inside Redis.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Broad client ecosystem$q$, $q$Official and community-maintained client libraries exist for nearly every major programming language.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Extremely fast in-memory performance for caching and real-time workloads$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Rich set of native data structures beyond simple key-value pairs$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Now available under AGPLv3, restoring OSI-recognized open-source licensing as of Redis 8$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Large ecosystem of client libraries and community tooling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Managed Redis Cloud reduces operational overhead for teams that do not want to self-host$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Built-in vector search suits modern AI and RAG use cases$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$The 2024 licensing change to SSPL/RSALv2 damaged community trust, even after the 2025 AGPL reversal$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$In-memory model means data sets are constrained by available RAM, raising costs at scale$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Some advanced enterprise features still require the commercial Redis Cloud or Redis Software tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$The Valkey fork (Linux Foundation) has pulled some contributors and users away from Redis$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Complex multi-node cluster configurations require real operational expertise$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Data durability requires careful persistence tuning between RDB and AOF trade-offs$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Is Redis free to use?$q$, $q$Yes. Redis Open Source is free to self-host under its current tri-license, which includes the AGPLv3 open-source license alongside RSALv2 and SSPLv1.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$What license does Redis use in 2026?$q$, $q$Redis 8 and later versions ship under a tri-license: AGPLv3, RSALv2, and SSPLv1, adopted in May 2025 after the March 2024 move away from BSD licensing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$What is the difference between Redis and Valkey?$q$, $q$Valkey is a community fork of Redis created by the Linux Foundation in response to Redis's March 2024 licensing change; it remains under the original BSD-style permissive license.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Who created Redis?$q$, $q$Salvatore Sanfilippo (antirez) created Redis in 2009; the commercial company behind it, now Redis Ltd., was founded in 2011.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$What does Redis Cloud cost?$q$, $q$Redis Cloud has a free tier (30 MB), Essentials plans from about 5 to 216 dollars per month, and Pro plans starting around 200 dollars per month.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Can I self-host Redis for free?$q$, $q$Yes, Redis Open Source can be self-hosted at no cost under its current AGPLv3-inclusive license.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$What is Redis commonly used for?$q$, $q$Caching, session storage, real-time analytics, message brokering, rate limiting, and increasingly vector search for AI applications.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Who owns Redis?$q$, $q$Redis Ltd. (formerly Redis Labs), headquartered in San Francisco, California, owns and develops Redis.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Application caching layer$q$, $q$Reduce database load and speed up response times by caching frequently accessed data in memory.$q$, $q$Backend and platform engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Real-time analytics and leaderboards$q$, $q$Use sorted sets and streams to power real-time rankings, counters, and event pipelines.$q$, $q$Gaming, adtech, and real-time application teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$AI and RAG vector backend$q$, $q$Store and query vector embeddings alongside operational data for retrieval-augmented generation applications.$q$, $q$AI/ML engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Redis Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted deployment","AGPLv3/RSALv2/SSPLv1 tri-license","Full data structures and persistence","Built-in search, JSON, and vector capabilities"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Redis Cloud Free$q$, $q$$0$q$, $q$monthly$q$, NULL, $q$["30 MB shared instance","100 ops/sec throughput","30 concurrent connections","No SLA, community support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Redis Cloud Essentials$q$, $q$From approximately $5 to $216$q$, $q$monthly$q$, NULL, $q$["Dedicated small-to-mid-size databases","Up to 12 GB capacity at higher tiers","Improved throughput vs free tier"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Redis Cloud Pro$q$, $q$From approximately $200$q$, $q$monthly$q$, NULL, $q$["Dedicated VPC infrastructure","Multi-AZ high availability","99.999% uptime SLA"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$Redis Enterprise/Software$q$, $q$Custom$q$, $q$annual/custom$q$, NULL, $q$["Self-managed on-premises or private cloud","Advanced compliance and support options","Custom SLAs"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Redis began as a personal project by Salvatore Sanfilippo in 2009 and has grown into one of the most widely deployed in-memory data stores in the world, used as a cache, primary database, message broker, and streaming engine by companies of all sizes.$q$, $q$The company behind Redis, Redis Ltd. (formerly Redis Labs), is headquartered in San Francisco and has roughly 1,500 employees. Its licensing history is notable: a March 2024 shift away from BSD to source-available licenses (RSALv2/SSPLv1) triggered the Valkey community fork, before Redis reversed course in May 2025 and adopted a tri-license including AGPLv3 for Redis 8 and later.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$features$q$, $q$Key Features$q$, 2, ARRAY[$q$Redis supports rich native data structures beyond simple key-value pairs, including hashes, lists, sets, sorted sets, streams, and geospatial indexes, all operating in memory for sub-millisecond latency.$q$, $q$Recent versions bundle capabilities that were previously separate Redis Stack modules, such as full-text search (RediSearch), native JSON support (RedisJSON), time-series data (RedisTimeSeries), and probabilistic data structures (RedisBloom), plus vector search for AI and RAG applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Redis Open Source is free to download and self-host under the current tri-license (AGPLv3, RSALv2, SSPLv1). For teams that prefer a managed service, Redis Cloud offers a free tier (30 MB), Essentials plans from about 5 to 216 dollars per month, and Pro plans starting around 200 dollars per month with multi-AZ high availability and a 99.999 percent SLA.$q$, $q$Enterprise and self-managed Redis Software deployments are available with custom pricing for organizations with specific compliance, on-premises, or private-cloud requirements.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('edd1bac6-16dc-4bda-b79f-aadb3cc602d0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Multi-project and subproject management$q$, $q$Organize related work across parent and child projects with independent configuration.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Role-based access control$q$, $q$Granular permissions let administrators control what each role can view or edit per project.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Gantt charts and calendars$q$, $q$Visual scheduling tools help teams track deadlines and dependencies.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Time tracking$q$, $q$Built-in time logging supports effort tracking and reporting against issues and projects.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Per-project wikis and forums$q$, $q$Native documentation and discussion spaces live alongside each project's issues.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Version control integration$q$, $q$Built-in repository browser and diff viewer connect to Git, Subversion, Mercurial, CVS, and Bazaar.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Customizable issue tracker$q$, $q$Configurable fields, statuses, and workflows adapt Redmine to varied team processes.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Plugin ecosystem$q$, $q$A large library of community plugins extends Redmine with agile boards, reporting, and automation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Completely free and open source with no per-user licensing fees$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Highly customizable issue trackers, workflows, and fields$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Built-in Gantt charts, calendars, and time tracking$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Native integration with major version control systems$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Large plugin ecosystem for extending functionality$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Self-hosting gives organizations full control over their data$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Requires self-hosting and server maintenance, or a paid third-party host$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Interface feels dated compared to modern SaaS project management tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$No official vendor support; relies on community and third parties$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Steeper setup and configuration learning curve than turnkey SaaS tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Fewer native integrations with modern SaaS apps than commercial competitors$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Mobile experience is limited compared to native mobile-first tools$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Is Redmine free?$q$, $q$Yes, Redmine is free and open source under the GNU General Public License v2, with no licensing fees for the core software.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Who created Redmine?$q$, $q$Redmine was created by Jean-Philippe Lang and first released in 2006.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$What is Redmine built with?$q$, $q$Redmine is built on the Ruby on Rails framework and supports MySQL, PostgreSQL, and SQLite databases.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Can Redmine integrate with Git?$q$, $q$Yes, Redmine includes native integration with Git, Subversion, Mercurial, CVS, and Bazaar, plus a built-in repository browser.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Does Redmine offer official cloud hosting?$q$, $q$Redmine itself does not offer official managed hosting; several third-party providers offer paid Redmine hosting and support.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$What databases does Redmine support?$q$, $q$Redmine supports MySQL, PostgreSQL, and SQLite, among other databases, due to its cross-database Rails architecture.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Is Redmine similar to Jira?$q$, $q$Yes, Redmine is often used as a free, self-hosted, open-source alternative to commercial issue trackers like Jira.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Does Redmine support plugins?$q$, $q$Yes, Redmine has a large community plugin ecosystem that extends its core functionality significantly.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Software development issue tracking$q$, $q$Track bugs, features, and releases with configurable workflows tied directly to source repositories.$q$, $q$Software development teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$IT and operations project management$q$, $q$Manage internal IT projects, subprojects, and time tracking across multiple teams.$q$, $q$IT departments and operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Budget-conscious education and non-profit project tracking$q$, $q$Run structured project management without per-seat licensing costs.$q$, $q$Educational institutions, government agencies, and non-profits$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Community/Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["GPLv2 licensed, self-hosted","Full feature set with no gating","Access to community plugins and themes","No official vendor support included"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$Third-party managed hosting$q$, $q$Varies by provider$q$, $q$varies$q$, NULL, $q$["Hosting and maintenance handled externally","Optional support contracts","Not an official Redmine offering"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Redmine has been developed since 2006 by creator Jean-Philippe Lang and an open-source community, growing into one of the most widely used self-hosted project management and issue-tracking platforms, especially among software teams comfortable running their own infrastructure.$q$, $q$As a GPLv2-licensed project rather than a company product, Redmine has no official pricing, sales team, or vendor lock-in; its ongoing development, plugin ecosystem, and documentation are maintained collaboratively by contributors and third-party hosting providers.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$features$q$, $q$Key Features$q$, 2, ARRAY[$q$Redmine supports multiple simultaneous projects and subprojects, role-based access control, Gantt charts, calendars, and time tracking, giving teams the scheduling and reporting tools common to larger commercial PM tools.$q$, $q$It also integrates directly with version control systems like Git and Subversion, includes per-project wikis and forums, and offers a highly configurable issue tracker with customizable fields, statuses, and workflows, extendable further through a large community plugin ecosystem.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Redmine itself is entirely free under the GPLv2 open-source license, with no tiers, seats, or subscription fees for the core software.$q$, $q$Costs, if any, come from self-hosting infrastructure (servers, storage, maintenance) or from optional third-party managed hosting, support, or premium plugin providers, none of which are operated by a central Redmine company.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('82a64b4e-889f-499f-9da5-e2f83f5d9d43', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Redoc open-source renderer$q$, $q$Free, MIT-licensed three-panel API reference documentation generator for OpenAPI and other spec formats.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Developer portal builder (Revel)$q$, $q$Combine Markdown documentation, custom React pages, and localization into a full developer portal.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$API catalog and governance (Reef)$q$, $q$Discover, catalog, and score APIs across an organization for consistency and compliance.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Multi-format spec support$q$, $q$Documentation generation for OpenAPI, AsyncAPI, GraphQL, and SOAP specifications.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Built-in linting and validation$q$, $q$Automated spec linting helps enforce API design standards before publishing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Mock servers$q$, $q$Generate mock API servers directly from OpenAPI specs for testing and prototyping.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$SSO, RBAC, and AI search$q$, $q$Enterprise-tier access controls and AI-powered documentation search for larger teams.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$API reliability monitoring (Respect)$q$, $q$Usage-based monitoring product for tracking API uptime and reliability.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Free, MIT-licensed Redoc renderer is genuinely open source and widely adopted$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Clean, professional three-panel documentation output$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Modular pricing lets teams pay only for the products they need$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Strong OpenAPI governance and linting tooling$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Supports multiple spec formats beyond just OpenAPI$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Enterprise tier includes SSO and RBAC for larger organizations$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Full commercial platform pricing is seat-based and can add up for larger teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Advanced governance and AI search features are Enterprise-only$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Add-on products (Revel, Reef) are priced separately from the core plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Custom Enterprise+ pricing requires a sales conversation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Usage-based Respect monitoring adds another cost dimension to budget for$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Smaller ecosystem and community than more established SaaS competitors like ReadMe$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Is Redoc free?$q$, $q$Yes, Redoc, the underlying renderer, is free and open source under the MIT license and can be self-hosted or embedded.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$What does Redocly cost?$q$, $q$Redocly's commercial platform starts at $10/seat/month (Pro) and $24/seat/month (Enterprise), with custom Enterprise+ pricing available.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$What is the difference between Redoc and Redocly?$q$, $q$Redoc is the free open-source rendering engine; Redocly is the company's full commercial platform for portals, governance, and API management.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Does Redocly support AsyncAPI?$q$, $q$Yes, in addition to OpenAPI, Redocly supports AsyncAPI, GraphQL, and SOAP documentation.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$What is Reef?$q$, $q$Reef is Redocly's API catalog and governance product, offering discovery and scorecards across an organization's APIs.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$What is Revel?$q$, $q$Revel is Redocly's developer portal builder, supporting Markdown docs, custom React pages, and localization.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Does Redocly offer single sign-on?$q$, $q$Yes, SSO and guest SSO are included starting at the Enterprise tier.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Who founded Redocly and where is it based?$q$, $q$Redocly was founded in 2017 and is headquartered in Austin, Texas.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Publishing OpenAPI reference documentation$q$, $q$Render clean, accurate API reference docs directly from OpenAPI specifications.$q$, $q$API platform and developer experience teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Building developer portals$q$, $q$Combine reference docs, guides, and custom pages into a unified developer portal.$q$, $q$Companies exposing public or partner APIs$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$API governance at scale$q$, $q$Catalog and score APIs across many teams to enforce design and documentation standards.$q$, $q$Enterprise API governance and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Free (Redoc OSS)$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["MIT-licensed renderer","Self-hosted or embeddable","Core OpenAPI reference rendering"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Pro$q$, $q$$10/seat$q$, $q$monthly$q$, NULL, $q$["1 project, 100 pages","Custom domain hosting","Mock servers","Linting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Enterprise$q$, $q$$24/seat$q$, $q$monthly$q$, NULL, $q$["500 pages","SSO, guest SSO, RBAC","AI-powered search and analytics","MCP server support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Enterprise+$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Data residency options","Single-tenant hosting","Security questionnaires and procurement support","Dedicated professional services"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$Respect (API monitoring)$q$, $q$Free up to 1,000 requests/month; paid tiers $100 to $1,000+/month$q$, $q$monthly$q$, NULL, $q$["Usage-based API reliability monitoring","Commitment tiers with overage pricing"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Founded in 2017 and based in Austin, Texas, Redocly grew out of Redoc, a free, MIT-licensed OpenAPI renderer that remains one of the most widely used API documentation tools on GitHub and npm.$q$, $q$Beyond the free renderer, Redocly's commercial platform combines Redoc, Revel (developer portals), and Reef (API catalog and governance) into modular, seat-based products for engineering and API platform teams.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$features$q$, $q$Key Features$q$, 2, ARRAY[$q$The core Redoc renderer turns OpenAPI, AsyncAPI, GraphQL, and SOAP specifications into clean three-panel reference documentation, while Revel adds full developer portal capabilities including Markdown docs and custom React pages.$q$, $q$Reef provides API catalog management and governance scorecards, and Enterprise plans add SSO, RBAC, AI-powered search, and analytics for larger organizations managing many APIs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('01c9cb83-d21b-4761-b79e-7d589ccbad23', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Redoc itself is free and open source under the MIT license. Redocly's commercial platform starts at 10 dollars per seat per month (Pro) and 24 dollars per seat per month (Enterprise), with a custom-priced Enterprise+ tier for large organizations.$q$, $q$Add-on products Revel and Reef are priced separately per seat, or bundled as Realm; a separate usage-based Respect product for API monitoring starts free for up to 1,000 requests per month and scales to 1,000 dollars per month for 500,000 requests.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Automatic backlinking$q$, $q$Linking to another note automatically creates a reciprocal backlink, forming a connected network of ideas.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$End-to-end encryption$q$, $q$Notes are encrypted on-device so that even Reflect's team cannot access user content.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$AI-powered summarization and chat$q$, $q$Built-in AI tools help summarize notes and let users query their notes conversationally.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Daily notes and graph view$q$, $q$Daily journaling entries and a visual graph help users track and explore their thinking over time.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Cross-platform apps$q$, $q$Native apps are available for web, macOS, Windows, and iOS.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Fast quick capture and search$q$, $q$The app is optimized for minimal friction between having a thought and recording it.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Third-party integrations$q$, $q$Connects with Readwise, Google Calendar, and Kindle highlights to pull external content into notes.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$True end-to-end encryption, unusual among mainstream note-taking apps$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Automatic backlinking creates a genuinely networked note structure$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Fast, minimalist interface focused on quick capture$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Single flat-rate plan with no feature gating$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$AI features included at no extra cost$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Built by an experienced founder (Clearbit) with a small, focused team$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$No permanently free tier, only a 14-day trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Small team size may mean slower feature development and support response$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Lacks some advanced organizational features found in tools like Notion$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Mobile app support is currently limited to iOS, with no native Android app$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Steeper conceptual learning curve for users unfamiliar with networked note-taking$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Smaller integration ecosystem than larger competitors$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Is Reflect free?$q$, $q$Reflect has no permanent free tier but offers a 14-day free trial; after that it costs $10/month billed annually.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Who created Reflect?$q$, $q$Reflect was founded in 2021 by Alex MacCaw, previously founder of Clearbit, along with co-founders Ocavue and Vojtech Rinik.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Does Reflect encrypt notes?$q$, $q$Yes, Reflect uses end-to-end encryption so notes are only readable by the user, not by Reflect itself.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Does Reflect have an Android app?$q$, $q$Reflect currently offers an iOS app but no native Android app.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$What is backlinking in Reflect?$q$, $q$Backlinking automatically creates a reciprocal link in a referenced note whenever you link to it from another note.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Does Reflect include AI features?$q$, $q$Yes, AI summarization and chat features are included in Reflect's single subscription plan.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Can I import Readwise highlights into Reflect?$q$, $q$Yes, Reflect integrates with Readwise as well as Google Calendar and Kindle highlights.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Where is Reflect based?$q$, $q$Reflect is based in Austin, Texas, with a small team of about three to four people.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Personal knowledge management$q$, $q$Build a connected, backlinked network of notes and ideas over time.$q$, $q$Knowledge workers and researchers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Journaling with backlinked daily notes$q$, $q$Capture daily thoughts and automatically connect them to related notes and topics.$q$, $q$Individuals building a personal journaling habit$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Research and reading-highlight capture$q$, $q$Pull highlights from Readwise and Kindle directly into a connected notes system.$q$, $q$Readers and researchers who annotate heavily$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Standard Plan$q$, $q$$10/month$q$, $q$annual$q$, NULL, $q$["All features included","AI summarization and chat","End-to-end encryption","iOS, macOS, Windows, and web apps","Integrations with Readwise, Google Calendar, Kindle"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$Free Trial$q$, $q$Free$q$, $q$14 days$q$, NULL, $q$["Full feature access","No tiered restrictions during trial period"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Reflect was founded in 2021 by Alex MacCaw, previously founder of Clearbit, alongside co-founders Ocavue and Vojtech Rinik, and publicly launched in April 2022 as a fast, networked note-taking app.$q$, $q$The company remains a small, Austin, Texas-based team of roughly three to four people, positioning Reflect as a founder-led, privacy-focused alternative to larger note-taking platforms.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$features$q$, $q$Key Features$q$, 2, ARRAY[$q$Reflect's defining feature is automatic backlinking: linking one note to another creates a reciprocal link in both notes, forming a network of connected ideas rather than a folder hierarchy.$q$, $q$The app includes end-to-end encryption, daily notes, a visual graph view, AI-powered summarization and chat, and integrations with Readwise, Google Calendar, and Kindle highlights, all included in a single plan.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('19599bd9-0e9f-44d9-89bc-3dc73d9018b8', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Reflect uses a single, flat-rate pricing model at 10 dollars per month when billed annually, which includes every feature: AI tools, end-to-end encryption, mobile apps, and integrations.$q$, $q$There is no permanent free tier, but Reflect offers a 14-day free trial with full feature access before requiring a subscription.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$AI-generated personalized outreach$q$, $q$AI agents draft outbound email content tailored to individual prospects at scale.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$220M+ B2B contact database$q$, $q$A large proprietary contact database powers prospect targeting and research.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Multi-channel outreach sequencing$q$, $q$Automated cadences coordinate follow-ups across email and other channels.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$AI sales agents$q$, $q$Autonomous agents handle portions of the prospecting workflow to reduce manual SDR effort.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$RegieOne unified platform$q$, $q$Combines contact data, AI agents, and content generation into a single workflow, launched in 2025.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$CRM and sales stack integration$q$, $q$Connects with common CRM and sales engagement tools used by revenue teams.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Pipeline and ARR analytics$q$, $q$Reporting tools track the impact of AI-driven outreach on pipeline and revenue.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Combines contact data and AI content generation in one platform$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Backed by well-known VCs with substantial funding (over $65M total)$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Reported strong ARR growth (around 300% YoY near its Series B)$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$RegieOne consolidates previously separate tools into one workflow$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Built by founders with both AI and enterprise sales backgrounds$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Designed to significantly reduce manual SDR prospecting workload$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$High per-seat pricing with a 10-seat minimum makes it costly for small teams$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Force Multiplier Rep tier at $499/user/month is a significant investment$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Enterprise RegieOne pricing is not transparent and requires a sales conversation$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Primarily suited to mid-market and enterprise sales orgs, less accessible to solo users or startups$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$AI-generated outreach content still requires human review for accuracy and tone$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Competitive category with well-funded rivals like Outreach, Salesloft, and Apollo$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$What does Regie.ai cost?$q$, $q$The entry-level AI SEP plan starts at $180/user/month with a 10-seat minimum, roughly $21,600/year before add-ons.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Who founded Regie.ai?$q$, $q$Regie.ai was founded in 2020 by Dr. Srinath Sridhar and Matt Millen.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$What is RegieOne?$q$, $q$RegieOne is Regie.ai's unified AI sales prospecting platform, introduced in 2025, combining contact data, AI agents, and content generation.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$How much funding has Regie.ai raised?$q$, $q$Regie.ai has raised approximately $65.6 million total, including a $30 million Series B round in February 2025.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Where is Regie.ai based?$q$, $q$Regie.ai is headquartered in San Francisco, California.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Does Regie.ai include a contact database?$q$, $q$Yes, Regie.ai's platform includes access to a database of more than 220 million B2B contacts.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Is there a free plan?$q$, $q$Regie.ai does not publicly list a free tier; pricing starts at $180/user/month with a 10-seat minimum.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Who are Regie.ai's competitors?$q$, $q$Competitors include Outreach, Salesloft, Apollo, and other emerging AI SDR and sales engagement tools.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$B2B outbound sales prospecting automation$q$, $q$Automate research, content creation, and outreach for outbound sales development teams.$q$, $q$B2B sales development (SDR) teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$AI-personalized email sequencing$q$, $q$Generate and sequence personalized multi-touch email campaigns at scale.$q$, $q$Sales and revenue operations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Enterprise sales development scaling$q$, $q$Deploy AI agents to augment or extend the capacity of an SDR organization.$q$, $q$Mid-market and enterprise sales leaders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$AI SEP$q$, $q$$180/user/month (10-seat minimum)$q$, $q$monthly (annual contracts typical)$q$, NULL, $q$["Core AI sales engagement features","Access to contact database","Multi-channel outreach sequencing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$Force Multiplier Rep$q$, $q$$499/user/month$q$, $q$monthly (annual contracts typical)$q$, NULL, $q$["Advanced AI agent automation","Deeper prospecting workflow coverage"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$RegieOne Enterprise$q$, $q$Custom$q$, $q$annual/custom$q$, NULL, $q$["Full unified platform","Custom contract terms","Dedicated enterprise support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Regie.ai was founded in 2020 by Dr. Srinath Sridhar and Matt Millen and is headquartered in San Francisco, employing roughly 100 people as of late 2025. The company has raised about 65.6 million dollars in total funding, including a 30 million dollar Series B in February 2025.$q$, $q$The platform combines a 220 million-plus contact database with AI agents for prospecting, content generation, and outreach sequencing, unified in 2025 under a platform called RegieOne.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$features$q$, $q$Key Features$q$, 2, ARRAY[$q$Regie.ai's AI agents research prospects and draft personalized outbound email content, then sequence multi-channel follow-ups automatically, reducing manual SDR workload.$q$, $q$RegieOne ties together the contact database, AI content generation, and outreach automation into one workflow, with reporting on pipeline and ARR impact for sales leaders.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('50a14386-9f18-49e2-abdb-80c88d9cb7a2', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Regie.ai's entry-level AI SEP plan starts at 180 dollars per user per month with a 10-seat minimum, roughly 21,600 dollars per year before add-ons.$q$, $q$The Force Multiplier Rep tier costs 499 dollars per user per month for deeper AI agent automation, while full RegieOne enterprise deployments are custom-priced.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Flow-based course structure$q$, $q$Combine static content and interactive quizzes or exercises into structured, sequenced learning flows.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Sandboxed auto-graded coding exercises$q$, $q$Execute and automatically grade student code submissions in a sandboxed environment, including plotting support.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Git-integrated course content$q$, $q$Author course material in YAML and Markdown and manage changes with Git version control.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Built-in grade book and calendar$q$, $q$Track student grades and course scheduling directly within the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Live in-class quizzes$q$, $q$Run real-time quizzes during live class sessions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Multi-course hosting$q$, $q$Host multiple independent courses on a single RELATE installation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$XMPP-based in-class messaging$q$, $q$Support real-time classroom communication through XMPP messaging.$q$, 6);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Completely free and open source$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Purpose-built for technical and STEM courses with coding assignments$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Git-based version control for course content$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Supports sandboxed automatic grading of code submissions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Flexible, simple text-based authoring format$q$, 4);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Can host multiple courses on a single installation$q$, 5);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Requires self-hosting and Django technical expertise to deploy$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Niche academic tool with limited adoption outside its creator's courses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$No commercial support or vendor backing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Less polished user interface than mainstream commercial LMS platforms$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Smaller community and documentation base than Moodle or Canvas$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Not designed for non-technical or K-12 educational contexts$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Is RELATE free?$q$, $q$Yes, RELATE is free and open source, distributed via GitHub for self-hosting.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Who created RELATE?$q$, $q$RELATE was created by Andreas Kloeckner, a computer science professor.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$What is RELATE built with?$q$, $q$RELATE is built on the Python-based Django web framework.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Does RELATE support auto-graded coding assignments?$q$, $q$Yes, RELATE supports sandboxed code execution with automatic grading and plotting.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Can I self-host RELATE?$q$, $q$Yes, self-hosting is the primary and intended deployment model for RELATE.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Is RELATE a full LMS replacement?$q$, $q$RELATE is a specialized courseware tool, more niche and technical than general-purpose systems like Canvas or Moodle.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$How is course content authored in RELATE?$q$, $q$Course content is authored in YAML and Markdown and versioned using Git.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Does RELATE support multiple courses?$q$, $q$Yes, a single RELATE installation can host multiple independent courses.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$University STEM and programming course delivery$q$, $q$Deliver structured, interactive coursework for technical subjects with coding components.$q$, $q$University instructors teaching STEM or computing courses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Auto-graded coding assignment hosting$q$, $q$Run sandboxed, automatically graded programming exercises for students.$q$, $q$Computer science and engineering educators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Self-hosted academic courseware$q$, $q$Deploy a free, customizable courseware platform without vendor licensing costs.$q$, $q$Technically capable academic departments and instructors$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$Open Source$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Self-hosted deployment","Full feature set","GitHub-distributed source code","No licensing fees"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RELATE is an open-source Django courseware platform created by Andreas Kloeckner, with development documented from 2014 through 2025, primarily used for delivering technical and STEM university courses online.$q$, $q$Unlike mainstream commercial learning management systems, RELATE is a niche academic tool with no company, sales team, or pricing structure behind it; it is distributed freely on GitHub for self-hosting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$features$q$, $q$Key Features$q$, 2, ARRAY[$q$RELATE organizes courses into flows, sequences of static content and interactive elements such as quizzes and sandboxed, auto-graded coding exercises, well suited to programming-heavy coursework.$q$, $q$Course content is authored in YAML and Markdown and versioned with Git, and the platform includes a grade book, class calendar, live in-class quizzes, and support for hosting multiple courses on one installation.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RELATE is entirely free and open source, with no licensing fees, tiers, or commercial vendor.$q$, $q$Any cost comes from self-hosting infrastructure and the technical effort required to deploy and maintain a Django application.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('9bf9becd-f896-4366-81eb-031d10afdd43', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Cloud-native hosting on Microsoft Azure$q$, $q$RelativityOne runs as a secure, elastically scalable SaaS platform hosted on Azure.$q$, 0);
