INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Flexible commitment pricing$q$, $q$Customers can choose pay-as-you-go pricing or discounted 1-year and 3-year commitments.$q$, 3);
