INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Litigation, investigation, and compliance workflows$q$, $q$Purpose-built workflows support e-discovery across multiple legal and regulatory use cases.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Large partner and reseller ecosystem$q$, $q$A broad network of implementation and consulting partners supports RelativityOne deployments.$q$, 6);
