INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Pricing is not publicly disclosed, requiring a sales process to get quotes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Enterprise-oriented positioning makes it costly and complex for small legal teams$q$, 1);
