INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Competitive category with strong alternatives like Everlaw and DISCO$q$, 5);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$What is RelativityOne?$q$, $q$RelativityOne is the cloud-based, Azure-hosted version of Relativity's e-discovery and legal data intelligence platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$How much does RelativityOne cost?$q$, $q$RelativityOne pricing is custom and not publicly disclosed; it is based on pay-as-you-go or 1-3 year committed contracts.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Who owns RelativityOne?$q$, $q$RelativityOne is owned by Relativity, formerly known as kCura, headquartered in Chicago, Illinois.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$When was Relativity founded?$q$, $q$The company was founded in 2001 as kCura and rebranded to Relativity in 2017.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Is RelativityOne cloud-based?$q$, $q$Yes, RelativityOne is hosted on Microsoft Azure as a SaaS platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Does Relativity offer on-premises deployment?$q$, $q$Yes, Relativity Server remains available as an on-premises deployment option.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Who uses RelativityOne?$q$, $q$Law firms, corporations, and government agencies, including the U.S. Department of Justice and numerous Fortune 100 companies, use RelativityOne.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Does RelativityOne include AI features?$q$, $q$Yes, RelativityOne includes AI-powered document review and analytics capabilities.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Corporate litigation e-discovery$q$, $q$Manage the discovery, review, and analysis of electronic data in litigation matters.$q$, $q$Corporate legal departments and outside counsel$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Internal investigations data review$q$, $q$Review and analyze large volumes of data during internal corporate investigations.$q$, $q$Compliance and internal investigations teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Regulatory compliance document analysis$q$, $q$Analyze and organize documents to support regulatory compliance and reporting obligations.$q$, $q$Regulatory affairs and compliance teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$Pay-as-you-go$q$, $q$Custom, usage-based$q$, $q$consumption-based$q$, NULL, $q$["Flexible short-term consumption pricing","No long-term commitment required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$1-Year Commitment$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Discounted pricing versus pay-as-you-go","Predictable annual costs"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$3-Year Commitment$q$, $q$Custom$q$, $q$multi-year$q$, NULL, $q$["Greatest discount for long-term commitment","Predictable multi-year costs"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$RelativityOne traces back to kCura, a Chicago software firm founded in 2001 by Andrew Sieja, which rebranded as Relativity in 2017 after its flagship e-discovery product. The company now has roughly 1,800-1,900 employees and remains headquartered in Chicago.$q$, $q$RelativityOne is the cloud-native, Azure-hosted version of the company's e-discovery platform, serving more than 180,000 users across 40-plus countries, including major law firms, corporations, and government agencies.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform combines document review workflows, AI-assisted categorization and prioritization, data visualization, and case analytics to help legal teams manage large volumes of electronic data in litigation, investigations, and compliance matters.$q$, $q$RelativityOne is hosted on Microsoft Azure for elastic scalability, while Relativity Server remains available as an on-premises option for organizations with specific data residency needs.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6b59bfb3-5ea0-4d33-92fe-b141944faacf', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$RelativityOne pricing is not publicly disclosed and is structured around enterprise sales engagements, with customers choosing between pay-as-you-go consumption pricing or discounted 1-year or 3-year commitments.$q$, $q$Final cost depends on factors such as data volume, number of users, and workspace configuration, determined through direct consultation with Relativity's sales team.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Multiple checking accounts$q$, $q$Open up to 20 accounts on Starter or up to 50 on Scale to separate funds by purpose.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Virtual and physical debit cards$q$, $q$Issue up to 50 Visa debit cards for granular team spend control.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Automated bill pay$q$, $q$Automate outgoing bill payments on Grow and Scale plans.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Same-day and standard ACH transfers$q$, $q$Move money via ACH with same-day options available on paid plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Free domestic wires$q$, $q$Grow and Scale plans include free outgoing domestic wire transfers.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$QuickBooks and Xero sync$q$, $q$Transaction data syncs directly into QuickBooks Online and Xero for reconciliation.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$High-yield savings accounts$q$, $q$Up to two savings accounts with APY reaching approximately 2.68% on the Scale plan.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$No overdraft or minimum balance fees$q$, $q$All plans, including the free Starter tier, carry no overdraft fees or minimum balance requirements.$q$, 7);
