INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Is Relay free to use?$q$, $q$Yes, Relay's Starter plan is free with no monthly fees, overdraft fees, or minimum balance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$What does Relay's Grow plan cost?$q$, $q$The Grow plan costs $30 per month and adds free domestic wires, automated bill pay, and same-day ACH.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$What does Relay's Scale plan cost?$q$, $q$The Scale plan costs $90 per month and raises the account limit to 50 with higher savings APY.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$How many accounts can I open with Relay?$q$, $q$Up to 20 checking accounts on Starter, or up to 50 on the Scale plan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Does Relay integrate with QuickBooks?$q$, $q$Yes, Relay syncs directly with QuickBooks Online and also with Xero.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Where is Relay headquartered?$q$, $q$Relay is headquartered in Toronto, Ontario, Canada.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$When was Relay founded?$q$, $q$Relay was founded in 2018.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Does Relay charge overdraft fees?$q$, $q$No, Relay does not charge overdraft fees on any of its plans.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Small business multi-account cash-flow management$q$, $q$Separate funds for taxes, payroll, and reserves across multiple dedicated checking accounts.$q$, $q$Small and mid-sized business owners$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Team expense control with virtual and physical cards$q$, $q$Issue individual debit cards to employees with spend controls tied to specific accounts.$q$, $q$Operations and finance teams managing employee spend$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Bookkeeping automation via accounting sync$q$, $q$Automatically sync transactions into QuickBooks Online or Xero to streamline reconciliation.$q$, $q$Bookkeepers and small business accountants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Starter$q$, $q$Free$q$, $q$n/a$q$, NULL, $q$["Up to 20 checking accounts","Basic ACH transfers","No monthly, overdraft, or minimum balance fees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Grow$q$, $q$$30/month$q$, $q$monthly$q$, NULL, $q$["Free domestic outgoing wires","Automated bill pay","Same-day ACH","Approximately 1.55% APY savings"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$Scale$q$, $q$$90/month$q$, $q$monthly$q$, NULL, $q$["Up to 50 checking accounts","Approximately 2.68% APY savings","Advanced automation and financial workflow tools"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Relay was founded in 2018 and is headquartered in Toronto, Ontario, Canada, offering an all-in-one business banking platform focused on multi-account cash-flow organization for small and mid-sized businesses.$q$, $q$Rather than competing on lending or investment products, Relay differentiates through account structure flexibility, integrated bill pay, and direct syncing with accounting software like QuickBooks Online and Xero.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$features$q$, $q$Key Features$q$, 2, ARRAY[$q$Relay lets businesses open up to 20 (Starter) or 50 (Scale) individual checking accounts to separate funds for taxes, payroll, and specific projects, along with up to 50 virtual or physical Visa debit cards for team spend control.$q$, $q$The platform supports ACH, wire, and check transfers in both directions, deposits from payment processors like Stripe, PayPal, and Square, and direct syncing with QuickBooks Online and Xero for bookkeeping.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('9a668def-7d55-49ba-9faf-7c5b9537b7a6', $q$pricing$q$, $q$Pricing$q$, 2, ARRAY[$q$Relay's Starter plan is free with no monthly fees, overdraft fees, or minimum balance, supporting up to 20 checking accounts and basic ACH.$q$, $q$The Grow plan costs $30/month and adds free domestic wires, automated bill pay, and same-day ACH, while the Scale plan at $90/month raises account limits to 50 and unlocks advanced automation and higher savings APY.$q$]::text[], 2);
